import json
import os

def lambda_handler(event, context):
    # Sample user data
    users = [
        {"id": 1, "name": "John Doe", "email": "john@example.com"},
        {"id": 2, "name": "Jane Smith", "email": "jane@example.com"},
        {"id": 3, "name": "Bob Johnson", "email": "bob@example.com"}
    ]
    
    # Get allowed origins from environment variable with secure defaults
    allowed_origins = os.environ.get('ALLOWED_ORIGINS', '').split(',')
    
    # If no origins configured, deny all (fail secure)
    if not allowed_origins or allowed_origins == ['']:
        return {
            'statusCode': 403,
            'body': json.dumps({'error': 'CORS not configured'})
        }
    
    # Get the origin from the request
    request_origin = event.get('headers', {}).get('origin') or event.get('headers', {}).get('Origin')
    
    # Validate origin against whitelist
    allowed_origin = None
    if request_origin:
        if '*' in allowed_origins:
            # Only allow wildcard in non-production environments
            environment = os.environ.get('ENVIRONMENT', 'production')
            if environment in ['development', 'dev', 'local']:
                allowed_origin = request_origin
        elif request_origin in allowed_origins:
            allowed_origin = request_origin
    
    # If no valid origin found, use the first allowed origin or deny
    if not allowed_origin and '*' not in allowed_origins:
        if allowed_origins:
            allowed_origin = allowed_origins[0]
        else:
            return {
                'statusCode': 403,
                'body': json.dumps({'error': 'Origin not allowed'})
            }
    
    # Set secure CORS headers
    headers = {
        'Content-Type': 'application/json',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY',
        'X-XSS-Protection': '1; mode=block',
        'Strict-Transport-Security': 'max-age=31536000; includeSubDomains'
    }
    
    # Add CORS headers only if origin is validated
    if allowed_origin:
        headers['Access-Control-Allow-Origin'] = allowed_origin
        headers['Access-Control-Allow-Methods'] = 'GET, OPTIONS'
        headers['Access-Control-Allow-Headers'] = 'Content-Type,X-Amz-Date,Authorization,X-Api-Key,X-Amz-Security-Token'
        headers['Access-Control-Max-Age'] = '3600'
        # Only include credentials if not using wildcard
        if allowed_origin != '*':
            headers['Access-Control-Allow-Credentials'] = 'true'
    
    # Handle preflight OPTIONS request
    if event.get('httpMethod') == 'OPTIONS' or event.get('requestContext', {}).get('http', {}).get('method') == 'OPTIONS':
        return {
            'statusCode': 200,
            'headers': headers,
            'body': ''
        }
    
    # Return user data with secure headers
    return {
        'statusCode': 200,
        'headers': headers,
        'body': json.dumps({
            'users': users,
            'count': len(users)
        })
    }